ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
CHOICE vague {
  full: { SELECT ?col ?uni (SUM(?cr) AS ?n) WHERE { ?s a :Students ; p:college ?col ; p:university ?uni . ?e a :Enrollments ; p:hasStudents ?s ; p:year ?y ; p:grade ?g ; p:hasCourses ?c . ?c p:credits ?cr . FILTER(STR(?y)="2021") FILTER(!REGEX(STR(?g),"F")) } GROUP BY ?col ?uni }
  component: { SELECT ?col (SUM(?cr) AS ?n) WHERE { ?s a :Students ; p:college ?col . ?e a :Enrollments ; p:hasStudents ?s ; p:year ?y ; p:grade ?g ; p:hasCourses ?c . ?c p:credits ?cr . FILTER(STR(?y)="2021") FILTER(!REGEX(STR(?g),"F")) } GROUP BY ?col }
  component_2: { SELECT ?uni (SUM(?cr) AS ?n) WHERE { ?s a :Students ; p:university ?uni . ?e a :Enrollments ; p:hasStudents ?s ; p:year ?y ; p:grade ?g ; p:hasCourses ?c . ?c p:credits ?cr . FILTER(STR(?y)="2021") FILTER(!REGEX(STR(?g),"F")) } GROUP BY ?uni }
}

PREFIX : <http://ambrosia.example.org/student#>
PREFIX p: <http://ambrosia.example.org/student/prop#>
CHOICE vague {
  full: { SELECT ?col ?uni (COUNT(?sid) AS ?n) WHERE { ?s a :Students ; p:college ?col ; p:university ?uni . ?e a :Enrollments ; p:hasStudents ?s ; p:student_id ?sid } GROUP BY ?col ?uni }
  component: { SELECT ?col (COUNT(?sid) AS ?n) WHERE { ?s a :Students ; p:college ?col . ?e a :Enrollments ; p:hasStudents ?s ; p:student_id ?sid } GROUP BY ?col }
  component_2: { SELECT ?uni (COUNT(?sid) AS ?n) WHERE { ?s a :Students ; p:university ?uni . ?e a :Enrollments ; p:hasStudents ?s ; p:student_id ?sid } GROUP BY ?uni }
}
